import {NgModule} from '@angular/core';
import {CommonModule} from '@angular/common';
import {FormsModule} from '@angular/forms';
import {IonicModule} from '@ionic/angular';
import {RouterModule, Routes} from '@angular/router';

import {RainsPage} from './rains.page';
import {RainDetailPage} from './rain-detail.page';
import {Storage} from '../shared';
import {PipesModule} from '../shared/pipes.module';
import {SharedModule} from '../shared';
import {NewInstancePage} from './modals/new-instance.page';

const RouteConfig: Routes = [
    {
        path: '',
        children: [
            {path: '', component: RainsPage},
            {path: ':id', component: RainDetailPage},
            {
                path: 'new-instance',
                component: NewInstancePage,
            },
        ],
    },
];

@NgModule({
    imports: [
        CommonModule,
        FormsModule,
        IonicModule,
        RouterModule.forChild(RouteConfig),
        PipesModule,
        SharedModule,
    ],
    declarations: [RainsPage, RainDetailPage, NewInstancePage],
    providers: [Storage],
})
export class RainsPageModule {}
