import {AfterViewInit, Component, ViewChild} from '@angular/core';
import {CompareManager, ProfileService, RadarService, RefreshManager, Storage} from '../shared';
import {ActivatedRoute, ParamMap} from '@angular/router';
import {Observable} from 'rxjs';
import {switchMap} from 'rxjs/operators';
import {RadarNode, RainNode} from 'raain-model';
import {IonModal} from '@ionic/angular';

// TODO let TEST_DETECTION = 0;

@Component({
    selector: 'app-rain-detail',
    templateUrl: 'rain-detail.page.html',
    styleUrls: ['rain-detail.page.scss'],
})
export class RainDetailPage implements AfterViewInit {
    @ViewChild(IonModal) modal: IonModal;
    public rainNode: RainNode;
    public compareManager: CompareManager;
    public refreshManager: RefreshManager;
    public toggleAdmin: boolean;
    public isAdmin: boolean;
    public toggleDetails: boolean;
    public isSimpleZone: boolean;
    public toggleCumulative: boolean;
    public availableProviders: string[] = [];
    public availableTimeSteps: number[] = [];
    public selectedProvider: string;
    public selectedTimeStep: number;
    protected rain$: Observable<RainNode>;

    constructor(
        private readonly activatedRoute: ActivatedRoute,
        public profileService: ProfileService,
        public radarService: RadarService,
        protected storage: Storage
    ) {}

    ngAfterViewInit(): void {
        this.profileService.refreshProfile().then((ignored) => {});
        this.subscribeToRainUpdates();
    }

    onChangeDetectionTest(rainNode: RainNode) {
        // TODO console.log(TEST_DETECTION++, 'onChangeDetectionTest');
        return '';
    }

    async toggleAdminChanged(_$event: any) {
        this.storage.set('raain-toggleAdmin', this.toggleAdmin);
        await this.profileService.refreshProfile();
        await this.initRain(this.rainNode);
    }

    async refresh(event?: any) {
        try {
            await this.profileService.refreshProfile();
            await this.initRain(this.rainNode);
        } catch (e) {
            /* empty */
        }

        if (event) {
            event.target.complete();
        }

        if (!this.profileService.isLoggedIn()) {
            return this.profileService.gotoLout();
        }
    }

    toggleCumulativeChanged($event: any) {
        this.storage.set('raain-toggleCumulative', this.toggleCumulative);
    }

    async loadProviders() {
        if (!this.rainNode?.id) {
            return;
        }

        try {
            const result = await this.profileService.getProviders(this.rainNode.id);
            this.availableProviders = result.providers;
            this.availableTimeSteps = result.timeStepInMinutes;

            // Load saved selections or use defaults
            this.selectedProvider =
                this.storage.get('raain-selectedProvider') ||
                (this.availableProviders.length > 0 ? this.availableProviders[0] : 'Raain');
            this.selectedTimeStep =
                this.storage.get('raain-selectedTimeStep') ||
                (this.availableTimeSteps.length > 0 ? this.availableTimeSteps[0] : 10);
        } catch (e) {
            console.error('Failed to load providers:', e);
            // Set fallback values
            this.availableProviders = ['Raain'];
            this.availableTimeSteps = [5, 10, 15, 30, 60];
            this.selectedProvider = 'Raain';
            this.selectedTimeStep = 10;
        }
    }

    async providerChanged($event: any) {
        this.storage.set('raain-selectedProvider', this.selectedProvider);
        console.log('Provider changed to:', this.selectedProvider);
        // Refresh data with new provider
        await this.refresh();
    }

    async timeStepChanged($event: any) {
        this.storage.set('raain-selectedTimeStep', this.selectedTimeStep);
        console.log('Time step changed to:', this.selectedTimeStep);
        // Refresh data with new time step
        await this.refresh();
    }

    private subscribeToRainUpdates() {
        // console.log('subscribeToRainUpdates', this.rain$);
        if (this.rain$) {
            return;
        }

        this.rain$ = this.activatedRoute.paramMap.pipe(
            switchMap((params: ParamMap) => this.profileService.getRain(params.get('id')))
        );

        this.rain$.subscribe(this.initRain.bind(this));
    }

    private async initRain(rainNode: RainNode) {
        this.toggleDetails = false;
        this.toggleAdmin = this.storage.get('raain-toggleAdmin');
        this.toggleCumulative = this.storage.get('raain-toggleCumulative');
        this.isAdmin = this.profileService.isAdmin();

        if (!rainNode) {
            return;
        }

        this.rainNode = rainNode;
        this.compareManager = new CompareManager(this.profileService);
        this.refreshManager = new RefreshManager(
            this.radarService,
            this.profileService,
            this.compareManager
        );
        this.compareManager.rainNode = this.rainNode;
        this.refreshManager.rainNode = this.rainNode;

        // For Simple Radar-Rain Zone :
        const radarLinks = rainNode.getLinks(RadarNode.TYPE);
        this.isSimpleZone = radarLinks.length === 1;

        // Load available providers and time steps
        await this.loadProviders();

        // Set provider and timeStep on refreshManager
        if (this.refreshManager) {
            this.refreshManager.provider = this.selectedProvider;
            this.refreshManager.timeStepInMinutes = this.selectedTimeStep;
        }

        this.toggleDetails = true;
    }
}
