import {Component, OnInit, ViewChild} from '@angular/core';
import {FidjStorageNode, ProfileService} from '../shared';
import {RainNode} from 'raain-model';
import {Router} from '@angular/router';
import {IonModal} from '@ionic/angular';
import {environment} from '../../environments/environment';

@Component({
    selector: 'app-rains',
    templateUrl: 'rains.page.html',
    styleUrls: ['rains.page.scss'],
})
export class RainsPage implements OnInit {
    @ViewChild(IonModal) modal: IonModal;

    public rainsInfoAlreadyViewed: any = {};
    public sessionData: FidjStorageNode;
    public rains: RainNode[] = [];
    public appVersion = environment.version;

    constructor(
        private router: Router,
        private profile: ProfileService
    ) {}

    ngOnInit() {
        this.refresh();
    }

    async refresh(event?: any) {
        try {
            this.sessionData = await this.profile.refreshProfile();
            if (this.sessionData.infos.rainsInfoAlreadyViewed) {
                this.rainsInfoAlreadyViewed = this.sessionData.infos.rainsInfoAlreadyViewed;
            }

            this.rains = await this.profile.getRains(this.profile.asTeamId);
        } catch (e) {
            console.error('refresh pb:', e);
        }
        if (event) {
            event.target.complete();
        }

        if (!this.profile.isLoggedIn()) {
            return this.profile.gotoLout();
        }
    }

    clickOnRain(rain: RainNode) {
        return this.router.navigate(['/rains', rain.id]);
    }

    async closeInfo(windowName: string) {
        this.rainsInfoAlreadyViewed[windowName] = true;
        if (!this.sessionData || !this.sessionData.infos) {
            return;
        }

        this.sessionData.infos.rainsInfoAlreadyViewed = this.rainsInfoAlreadyViewed;
        await this.profile.storeAll();
    }
}
